import { useEffect } from 'react';
import './App.css';

function App() {
  useEffect(()=>{
    fetch('http://localhost:8081/usuarios')
    .then(res => res.json())
    .then(data => console.log(data))
    .catch(err => console.log(err));
  },[])
  return (
    <div className="App">
      
    </div>
  );
}

export default App;
